"""
mkt-christ layer — Colossians chapters 1–4 (all missing verses)
Output: data/commentary/mkt-christ/colossians.json
Run: python3 scripts/zc-christ-colossians-1-4-full.py

Pre-existing: ch1v15, ch1v20, ch2v9, ch2v15, ch3v4 — merge_comm will skip these.

Interpretation decisions:
- Col 1:24 'what is lacking in Christ's afflictions' = missionary sufferings, not atoning;
  Paul's agon participates in Christ's ongoing work in the world, not supplementing the cross.
- Col 2:17 shadow/body (skia/soma) contrast: entire OT observance-system as shadow;
  Christ is the soma whose arrival ends the shadow's authority.
- Col 3:10 'renewed in the image of its Creator' = renewed into the image of Christ
  (who is himself the image of God, 1:15); the eschatological Adam-restoration.
- Household code (3:18–4:1) Christologized throughout by 'in the Lord' qualifiers.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {
  "1": {
    "1": "<p>Paul describes himself as 'an apostle of Christ Jesus by the will of God' — the source of the apostolic office is the Damascus-road encounter with the risen Christ (Acts 9:1-19; Gal 1:1: not from human beings nor through any human being but through Jesus Christ and God the Father who raised him from the dead). Every element of Paul's identity in this greeting is Christological: he is Christ's apostle, acting within God's will, co-writing with Timothy as brother in the same Christ.</p>",
    "2": "<p>'To the holy ones in Colossae, the faithful brothers and sisters in Christ' — the double location is the letter's Christological map: the community exists simultaneously in Colossae (a geopolitical location) and 'in Christ' (a theological location). The 'in Christ' (<em>en Christō</em>) is the foundational Pauline locative: the community's primary identity is constituted by their union with the risen Lord, not by their city, ethnicity, or social status. The grace and peace that Paul invokes are Christ's own gifts (grace from the Father and the Lord Jesus Christ — the two sources are one gift).</p>",
    "3": "<p>'We always give thanks to God, the Father of our Lord Jesus Christ, when we pray for you' — Christological definition of God: Paul does not pray to 'god in general' but to the God who is defined by his relation to Jesus Christ as Lord. 'The Father of our Lord Jesus Christ' is the specifically Christian name for God — the God who sent, raised, and exalted Jesus. Every prayer is Christologically mediated.</p>",
    "4": "<p>'Because we heard of your faith in Christ Jesus and the love you have toward all the saints' — faith in Christ Jesus (<em>pistis en Christō Iēsou</em>) is the root from which love for all the saints grows. The Christological structure: Christ is the object of trust, and trust in Christ generates a community-shaped love for everyone who belongs to him. The two virtues (faith, love) are bound together through their common Christological center.</p>",
    "5": "<p>'Because of the hope stored up for you in heaven, about which you heard before in the word of truth, the gospel' — the hope is in heaven because Christ is in heaven (3:1: Christ is seated at the right hand of God); the hope and the person share the same location. The 'word of truth, the gospel' is Christological proclamation — the announcement of Christ's death, resurrection, and lordship that creates the hope by disclosing its ground.</p>",
    "6": "<p>'The gospel is bearing fruit and growing in the whole world just as it is among you' — the global fruit-bearing is the risen Christ's mission executing itself through human proclamation (Matt 28:18-20: all authority in heaven and earth has been given to me, go therefore). The growth metaphor (auxanomenon) recalls Gen 1:28 and points forward to the new-creation order inaugurated by Christ's resurrection; the gospel's fruitfulness is the evidence of Christ's active lordship over the nations.</p>",
    "7": "<p>'Just as you learned it from Epaphras, our dear fellow servant who is a faithful servant of Christ on our behalf' — Epaphras's ministry is Christ's own ministry continued through a human agent. The titles — 'dear fellow servant' (<em>agapētos syndoulos</em>) and 'faithful servant of Christ' (<em>pistos diakonos tou Christou</em>) — identify him as participating in Christ's own diaconate (Mark 10:45: the Son of Man came not to be served but to serve); his faithfulness is measured against Christ's faithfulness.</p>",
    "8": "<p>'Who also told us of your love in the Spirit' — the love that characterizes the Colossian community is 'in the Spirit' (<em>en pneumati</em>), and the Spirit is the Spirit of Christ (Rom 8:9). The love is Christological in its origin: the Spirit produces what Christ himself is (Gal 5:22: the fruit of the Spirit is love), and the Spirit pours into the community the same love with which the Father loved the Son.</p>",
    "9": "<p>'For this reason, since the day we heard, we have not ceased praying for you and asking that you be filled with the knowledge of his will in all wisdom and spiritual understanding' — the wisdom and knowledge for which Paul prays are Christologically located: in Christ are hidden all the treasures of wisdom and knowledge (2:3). To pray for their being filled with wisdom is to pray for their being filled with Christ (2:10: in him you have been brought to fullness). The knowledge is not abstract but the knowledge of God's will — Christ himself being the will of God for humanity.</p>",
    "10": "<p>'So that you may live a life worthy of the Lord and please him in every way, bearing fruit in every good work and growing in the knowledge of God' — 'the Lord' (<em>tou kyriou</em>) is Christ; the ethical standard is Christ's own character and conduct. A 'life worthy of the Lord' is a life shaped by the cruciform pattern of the one who became servant for all (Phil 2:5-8). The fruit-bearing and growth recall v.6: the community's personal growth participates in the gospel's global growth.</p>",
    "11": "<p>'Being strengthened with all power according to his glorious might, for great endurance and patience, with joy' — the power that strengthens the community is resurrection power; Paul elsewhere identifies 'the power of God who raised Christ from the dead' as the operative force in the community's life (Eph 1:19-20). The endurance and patience that result are the Christological virtues — Christ endured the cross, despising its shame (Heb 12:2), and his patience is the model for theirs.</p>",
    "12": "<p>'Giving joyful thanks to the Father, who has qualified you to share in the inheritance of the saints in light' — God has made the community 'qualified' (<em>hikanōsanti</em>) for an inheritance; the qualification is through their union with Christ, who is himself the heir of all things (Heb 1:2). Their inheritance-share is participation in Christ's own inheritance. The 'light' domain recalls John's Christology: Christ is the light of the world (John 8:12); to share in the inheritance of light is to share in the domain Christ occupies.</p>",
    "13": "<p>'He has rescued us from the dominion of darkness and transferred us to the kingdom of the Son he loves' — the two kingdoms: darkness (the realm of the cosmic powers, the ruler of this age) and the kingdom of Christ the beloved Son. The 'transfer' (<em>metestēsen</em>) is the new birth and baptism as a political relocation: the community's allegiance, residence, and governing authority have changed; they now live under Christ's kingship. The Son's identity as 'beloved' echoes the baptism and transfiguration declarations (Matt 3:17; 17:5).</p>",
    "14": "<p>'In whom we have redemption, the forgiveness of sins' — redemption is not merely an event but a location: it is 'in him' (<em>en hō</em>), in the person of Christ. Forgiveness does not float free as a legal transaction but is bound to union with the one who bore the sin. The whole letter will unfold why this matters against the Colossian error: if forgiveness is in Christ alone, there is no supplementary cosmic-power appeasement needed.</p>",
    "16": "<p>'For in him all things were created, things in heaven and on earth, visible and invisible, whether thrones or dominions or rulers or authorities — all things were created through him and for him' — the pre-existent Son as cosmic agent and goal of creation. The specification of invisible cosmic powers (thrones, dominions, rulers, authorities) addresses the Colossian error directly: the very powers the false teachers are asking the community to court were themselves created by Christ and exist for him. They are subordinate, derivative realities; Christ is the Creator and goal of their existence.</p>",
    "17": "<p>'He is before all things, and in him all things hold together' — two Christological claims about the present: priority (pro panton — before everything in time and ontology) and cosmic coherence (synestēken — present tense: he is continuously holding together). The universe's structural integrity depends on Christ's continuous sustaining; without him, ontological disintegration. The Colossian powers are not the cosmic glue — Christ is.</p>",
    "18": "<p>'He is the head of the body, the church; he is the beginning, the firstborn from the dead, so that he might have the preeminence in all things' — three Christological titles in parallel: head (the source of authority and nourishment for the body-community), beginning (<em>archē</em> = first principle, the origin of new creation), firstborn from the dead (<em>prōtotokos ek tōn nekrōn</em> = pioneer of resurrection, with others to follow). The purpose clause is decisive: all of this is so that Christ might hold first place in everything — the anti-Colossian-error conclusion is built into the hymn itself.</p>",
    "19": "<p>'For in him God was pleased to have all fullness dwell' — the <em>plēroma</em> (fullness) language directly addresses the Colossian error: if any element of divine fullness were distributed across the cosmic hierarchy, the community would need to negotiate with those powers. Paul's counter-claim is that the entire pleroma — not a portion — dwells in Christ. There is nothing in the divine order that is not present in him; therefore, union with Christ is the single sufficient response to every spiritual need.</p>",
    "21": "<p>'And you, who were once alienated and hostile in mind, doing evil deeds' — the pre-Christ condition is described as threefold alienation: relational (alienated from God), intellectual (hostile in mind), and behavioral (evil deeds). This is the Adamic condition: humanity cut off from God through the fall, hostile in its thinking, expressing that hostility in its actions. The 'once' (<em>pote</em>) temporal marker is the Pauline before/after Christological contrast that marks the letter's ethical argument.</p>",
    "22": "<p>'He has now reconciled you in his body of flesh by his death, to present you holy and blameless and above reproach before him' — two Christological precisions: (1) the body of flesh (<em>tō sōmati tēs sarkos autou</em>) insists on the physical reality of the incarnate death; the reconciliation did not happen in a spiritual transaction but in a bodily execution; (2) the purpose is presentation — Christ will present the community spotless before God, as he himself is spotless; the community's holiness is derivative of his. This counters any spiritualized or docetic version of the atonement.</p>",
    "23": "<p>'If indeed you continue in the faith, stable and steadfast, not shifting from the hope of the gospel that you heard' — the conditional protects against the false teaching's pull. The 'hope of the gospel' is Christ himself (1:27: Christ in you, the hope of glory); to be 'moved from the hope of the gospel' is to be moved from Christ. Stability in faith is stability in Christ; the Colossian error threatened that stability by adding cosmic-power requirements to what Christ alone was supposed to supply.</p>",
    "24": "<p>'Now I rejoice in what I suffer for you, and I fill up in my flesh what is still lacking in the afflictions of Christ for the sake of his body, which is the church' — the most theologically dense verse in the letter. The 'afflictions of Christ' (<em>ta hysterēmata tōn thlipseōn tou Christou</em>) are not the atoning sufferings (which are complete and sufficient, vv. 20-22) but the missionary sufferings that Christ's body endures as it brings the gospel to the nations. Paul's suffering is participatory: by suffering for the Colossians, Paul is extending Christ's own presence into the situation, serving as Christ's own flesh for the community's sake.</p>",
    "25": "<p>'I became a servant of it according to the commission God gave me to present to you the word of God in its fullness' — Paul's <em>diakonia</em> (service, diaconate) is a Christological office: Christ himself is the archetypal servant (<em>diakonos</em>, Mark 10:45), and Paul's ministry extends Christ's servant-work to the Gentiles. The 'commission' (<em>oikonomia</em>) is the divine household-management plan, and Paul's role within it is Christologically determined — he exists to make the word about Christ fully known.</p>",
    "26": "<p>'The mystery that has been hidden throughout the ages and generations, but has now been disclosed to his holy ones' — the mystery is the hidden plan of God now revealed in Christ (cf. 2:2: the mystery of God, which is Christ). The entire sweep of Israel's history was the concealed trajectory toward Christ; now, at the turn of the ages, the disclosure has happened. The mystery is not esoteric spiritual knowledge available through ascent or angelic intermediaries — it is the public announcement of Christ crucified and risen.</p>",
    "27": "<p>'To them God chose to make known among the Gentiles how great are the riches of the glory of this mystery, which is Christ in you, the hope of glory' — the mystery's content is named: 'Christ in you, the hope of glory' (<em>Christos en hymin, hē elpis tēs doxēs</em>). Two explosive claims: (1) Christ inhabits the Gentile community — the Messiah's presence is no longer geographically localized in Jerusalem but indwelling communities throughout the empire; (2) this indwelling is the guarantee of eschatological glory — the hope is not a wish but a pledge.</p>",
    "28": "<p>'He is the one we proclaim, warning every person and teaching every person with all wisdom, so that we may present every person mature in Christ' — the entire Pauline mission is compressed: 'him we proclaim' (<em>hon katangellomen</em>). The object of proclamation is a person, not a philosophy or a program. The goal — 'present every person mature in Christ' (<em>teleion en Christō</em>) — is the Christological destination of all human formation; maturity is measured against Christ's stature (Eph 4:13: mature humanity, measured by the full stature of Christ).</p>",
    "29": "<p>'To this end I also toil, striving according to his working that works powerfully in me' — the power behind Paul's labor is Christ's own resurrection energy (<em>energeia</em>). Paul does not toil in his own strength; the risen Christ is working <em>in</em> Paul, and Paul's effort is the creaturely form of Christ's own activity. This is the Christological account of apostolic ministry: Christ as the primary agent, Paul as the responsive instrument.</p>"
  },
  "2": {
    "1": "<p>'For I want you to know how great a struggle I have for you, and for those at Laodicea, and for all who have not seen my face in person' — the agon (struggle) language echoes 1:29: Christ's energy working in Paul for the sake of communities he has never personally met. Paul's intercession and concern for distant communities is the Christological extension of Christ's own love for the scattered sheep; the body of Christ creates obligations of care across geographic distance.</p>",
    "2": "<p>'That their hearts may be encouraged, knit together in love, with all the riches of full assurance of understanding and the knowledge of God's mystery, which is Christ' — the climax: the mystery of God is explicitly identified as 'Christ' (<em>tou Christou</em>). All theological knowledge — understanding, assurance, the riches of divine wisdom — finds its destination and content in the person of Christ. The unity in love that Paul prays for is Christologically grounded: love for Christ (and the love that Christ is) binds the community together.</p>",
    "3": "<p>'In whom are hidden all the treasures of wisdom and knowledge' — the direct Christological counter to the Colossian false teaching: whatever esoteric wisdom the cosmic-power mystics claimed to offer was already fully present in Christ alone. 'Hidden' does not mean inaccessible but is the hiding-in-plain-sight of the mystery (1:26): Christ is the open secret in whom all wisdom resides, accessible to those who have him.</p>",
    "4": "<p>'I say this so that no one may deceive you with plausible-sounding arguments' — the Christological warning: any argument that seems to add to or supplement what Christ provides is, by definition, a deceptive argument, regardless of how persuasive it sounds. The criterion for evaluating Colossian teaching is sufficiency: is Christ sufficient, or must something else be added?</p>",
    "5": "<p>'For though I am absent from you in body, I am with you in spirit, rejoicing to see your order and the firmness of your faith in Christ' — 'faith in Christ' (<em>tēs eis Christon pisteōs hymōn</em>) is the structural stability of the community. The 'firmness' (<em>stereōma</em>) is a military term for a solid formation — the community's Christological trust is the formation that holds against the false teaching's assault. Paul's absent-in-body, present-in-spirit is itself a Christological reality: the body of Christ transcends physical proximity.</p>",
    "6": "<p>'Therefore, just as you received Christ Jesus the Lord, walk in him' — the reception of Christ Jesus as Lord (<em>parelabete ton Christon Iēsoun ton kyrion</em>) is the Pauline summary of conversion: trust in the specific person who is both the Messiah (Christ) and the sovereign ruler (Lord). The ethical imperative 'walk in him' is the working-out of that reception: life is lived within Christ, not merely influenced by Christ. The Christological logic: if you received <em>him</em>, live <em>in him</em>.</p>",
    "7": "<p>'Rooted and built up in him, and established in the faith, just as you were taught, abounding with thanksgiving' — the two architectural metaphors (rooted = agricultural stability; built up = construction) share Christ as their foundation and soil. The community's stability comes from being in Christ, not from navigating a hierarchy of cosmic powers. The thanksgiving that results from this stability is the community's ongoing Christological response: they are grateful because they have been given everything in him.</p>",
    "8": "<p>'See to it that no one takes you captive through philosophy and empty deceit, according to human tradition, according to the elemental spirits of the world, and not according to Christ' — the decisive Christological criterion: the test for any teaching is whether it is <em>kata Christon</em> (according to Christ). Human tradition and elemental spirits (<em>stoicheia tou kosmou</em>) are explicitly contrasted with Christ as alternative governing principles; anything 'not according to Christ' is categorically a vehicle for captivity.</p>",
    "10": "<p>'And you have been filled in him, who is the head of all rule and authority' — the fullness that false teaching scattered across the cosmic hierarchy is available in Christ alone. 'Filled in him' (<em>en autō peplērōmenoi</em>) — the perfect passive: they have been and remain in a state of fullness through their union with him. His headship over all rule and authority (the same powers being courted in the false teaching) means that union with him provides access to everything those powers could offer, without the need to negotiate with them directly.</p>",
    "11": "<p>'In him you were also circumcised with a circumcision not performed by human hands, by putting off the body of flesh, by the circumcision of Christ' — the 'circumcision of Christ' (<em>peritomē tou Christou</em>) is the Christ-enacted new-covenant circumcision: the cutting away of the entire body of sin (the flesh-dominated self) that happened at the cross. This spiritual circumcision happens 'in him' — in union with Christ's death — and is received, not performed. The contrast with 'human hands' (<em>cheiropoiētos</em>) counters any requirement for physical circumcision as a spiritual supplement.</p>",
    "12": "<p>'Having been buried with him in baptism, in which you were also raised with him through faith in the working of God who raised him from the dead' — the baptism narrative is the Christ-death-and-resurrection narrative applied sacramentally: the descent into the water is burial with Christ; the emergence is resurrection with Christ. The raising is 'through faith in the working of God who raised him' — the ground of the community's resurrection is God's resurrection of Christ; their new life is derivative of and dependent on his prior resurrection.</p>",
    "13": "<p>'And you, who were dead in your trespasses and the uncircumcision of your flesh, God made alive together with him, having forgiven all our trespasses' — the death condition (trespasses + fleshly uncircumcision = the Adamic state of sin-solidarity) contrasted with Christ-vivification. 'Made alive together with him' (<em>synezōopoiēsen... tō Christō</em>) — the corporate dimension: the community's new life is a participation in Christ's own resurrection life; they did not simply receive life, they were made alive in company with him.</p>",
    "14": "<p>'Having cancelled the written bond of our legal indebtedness, which stood against us with its decrees; he took it away, nailing it to the cross' — the cancellation of the <em>cheirographon</em> (the certificate of debt, the legal record of human liability before God's law) at the cross. Christ's death was a cosmic law-court event: the verdict against humanity was absorbed and cancelled in his death; the very document that condemned was nailed with him to the cross. Every legal claim against the community has been judicially removed.</p>",
    "16": "<p>'Therefore let no one pass judgment on you in questions of food and drink, or with regard to a festival, a new moon, or a Sabbath' — these regulations were the shadow of the coming Christ (v.17); once Christ has arrived, they no longer have judging authority over those who belong to him. To submit to their judgment-authority is to act as if Christ has not yet come. The Christological logic: the reality's arrival terminates the shadow's authority as a standard of evaluation.</p>",
    "17": "<p>'These are a shadow of the things to come, but the body belongs to Christ' — the <em>skia/sōma</em> contrast: the entire OT observance-system was a shadow cast by the approaching body (Christ); when the body arrives, the shadow has no independent existence or authority. The 'body' (<em>sōma</em>) is both 'the substance' (the reality that the shadow was projecting) and possibly a wordplay on Christ as the head of the body-church (1:18); the community is the body of Christ, and in that body they have the reality that all the shadows pointed to.</p>",
    "18": "<p>'Let no one disqualify you, insisting on asceticism and worship of angels, going on in detail about visions, puffed up without reason by his sensuous mind' — the false mysticism: a spirituality of angelic intermediaries, visionary ascent, and ascetic discipline that bypassed Christ entirely. The Christological diagnosis is in v.19: they have 'lost connection with the head.' The disqualification they offer is not Christ's disqualification but their own presumptuous judgment; only the Chief Shepherd (Christ) can disqualify from the race.</p>",
    "19": "<p>'And not holding fast to the head, from whom the whole body, nourished and knit together through its joints and ligaments, grows with a growth that is from God' — the head is Christ; the community's life, growth, and cohesion all flow from connection to him. To abandon or supplement the head is to cut off the source of all nourishment. The growth is from God (<em>auxanei tēn auxēsin tou theou</em>) — God-originated, Christ-channeled, body-expressed; the false teaching's supplementary mysticism offered growth from a different source, which is no growth at all.</p>",
    "20": "<p>'If with Christ you died to the elemental spirits of the world, why, as if you were still alive in the world, do you submit to its regulations?' — the logic of Christ-death applied to the community's behavior: their baptismal death with Christ (2:12) was specifically a death to the <em>stoicheia</em> (elemental spirits/forces) of the world. To submit to regulations designed to appease or navigate those powers is to act as if they had never died; it is a practical denial of their Christological death.</p>",
    "21": "<p>'Do not handle, do not taste, do not touch' — the ascetic prohibitions of the Colossian false teaching, quoted without endorsement. These commands have the form of piety but (as v.23 will show) no Christological basis; they are human commandments (<em>entalmata... anthrōpōn</em>) that Paul evaluates against the Christological criterion of 2:8 (<em>kata Christon</em>). Christ himself declared all foods clean (Mark 7:19) and taught that what enters the mouth does not defile.</p>",
    "22": "<p>'Referring to things that all perish as they are used — according to human precepts and teachings' — the perishability of the regulated items undermines the regulations: the foods that the false teachers were restricting were themselves destined to perish in use. The contrast is with Christ and his word, which do not perish (1 Pet 1:23: the living and abiding word of God); Christological reality is permanent, human teaching-systems are transient.</p>",
    "23": "<p>'These have indeed an appearance of wisdom in promoting self-made religion and asceticism and severity to the body, but they are of no value in stopping the indulgence of the flesh' — the final verdict on the Colossian false teaching: it looks spiritual (<em>en sophias</em>) but fails at the actual problem. The asceticism does not address the flesh (the sinful self-orientation); only union with Christ in his death does (3:3: your life is hidden with Christ in God; 3:5: put to death therefore what is earthly in you). The Christological alternative (ch. 3) is what actually works.</p>"
  },
  "3": {
    "1": "<p>'If then you were raised with Christ, seek the things that are above, where Christ is, seated at the right hand of God' — resurrection-life is Christological in direction: Christ the risen Lord is located at the right hand of God (the throne-position of Ps 110:1, fulfilled in the resurrection-exaltation, Acts 2:33-35). The community has been raised with him (2:12); their orientation must therefore match his location. 'Seek the things above' is not escapism but attention to the Christological reality that is more real than what is visible below.</p>",
    "2": "<p>'Set your minds on things above, not on things that are on earth' — the Christological imagination: the 'things above' are defined by Christ's location and character (v.1: where Christ is seated). To 'set your mind' (<em>phroneite</em>) on things above is to habituate the imagination toward Christ's reality; this is the renewal of the mind (Rom 12:2) applied through the Christological lens of the letter. The earthly things are not evil in themselves but cease to be the constituting frame of the community's self-understanding.</p>",
    "3": "<p>'For you died, and your life is now hidden with Christ in God' — the community's true existence is located in God through Christ: their biography has been relocated from the world's frame to the divine frame. 'Hidden with Christ in God' (<em>kekryptai syn tō Christō en tō theō</em>) — the perfect tense: completed and remaining hidden. Their social self (what the world sees and judges) is no longer their ultimate identity; their real life is where Christ is, secured within God himself. This is the deepest Christological anti-anxiety statement in the letter.</p>",
    "5": "<p>'Put to death therefore what is earthly in you: sexual immorality, impurity, passion, evil desire, and covetousness, which is idolatry' — the 'therefore' grounds the ethical imperative in the Christological indicative of vv. 1-4: because you have died with Christ and your life is hidden in God, enact that death experientially. The catalogue of vices corresponds to the old self under the dominion of darkness (1:13); their mortification is the ongoing application of the baptismal Christ-death. Covetousness as idolatry: it substitutes a created good for the Creator, which is the very structure of anti-Christological existence.</p>",
    "6": "<p>'Because of these things the wrath of God is coming' — the eschatological judgment that Christ himself taught (Matt 25:31-46) and that Paul regularly invokes as the horizon of ethical seriousness. The 'wrath of God' is not arbitrary punishment but the necessary response of holiness to persistent idol-worship; Christ who absorbed the wrath on the cross (Rom 3:25; 1 John 2:2) is also the Christ who will execute judgment at the parousia (2 Cor 5:10). The community that has been rescued from the wrath (1 Thess 1:10: Jesus who delivers us from the coming wrath) is called to live accordingly.</p>",
    "7": "<p>'In these you too once walked, when you were living in them' — the pre-Christ biography: the 'once' (<em>pote</em>) temporal marker is the Pauline before/after Christological contrast. The community once walked in the ways of the dominion of darkness (1:13); they have been transferred to the kingdom of the Son. The old walk is not their present identity; it is history, displaced by the Christ-event that relocated their life (v.3).</p>",
    "8": "<p>'But now you must put away all such things: anger, rage, malice, slander, and obscene talk from your mouth' — the 'but now' (<em>nyni de</em>) is the Christological temporal turning point: the transfer to Christ's kingdom (1:13) means a new behavioral regime. The vices listed are the expressions of the hostile mind (1:21) — the pre-Christ condition of enmity toward God and neighbor. Christ-transformation produces the opposite: the compassion, kindness, and love of 3:12-14.</p>",
    "9": "<p>'Do not lie to each other, since you have taken off the old self with its practices' — the aorist 'have taken off' (<em>apekdysamenoi</em>) identifies the stripping of the old self with the baptismal event (2:12); it is completed action, not an ongoing project. The old self is the self under the dominion of the flesh and death, the Adamic self that was oriented away from God; its practices were the vices of 3:5-8. The new community lives from the completed reality of the Christ-death already applied to the old self.</p>",
    "10": "<p>'And have put on the new self, which is being renewed in knowledge according to the image of its Creator' — Christ is the image of God (1:15); the new self is being renewed into conformity with Christ — who is himself the image. To be 'renewed in the image of the Creator' is to be renewed into the image of Christ, the new Adam (Rom 5:14; 1 Cor 15:45). The eschatological transformation is in process: the perfect 'put on' (completed event) combined with the present 'being renewed' (ongoing process) describes the already-not-yet structure of Christological formation.</p>",
    "11": "<p>'Here there is no Greek or Jew, circumcised or uncircumcised, barbarian, Scythian, slave or free — but Christ is all and in all' — the most compressed Christological summary in the letter: 'Christ is all and in all' (<em>panta kai en pasin Christos</em>). Every social, ethnic, and religious distinction that the old world used to organize reality has been superseded; Christ — not those categories — constitutes the community's identity. All is summed up in Christ (Eph 1:10); he is the measure, content, and frame of everything that matters.</p>",
    "12": "<p>'Therefore, as God's chosen ones, holy and beloved, put on compassionate hearts, kindness, humility, meekness, and patience' — the virtues are the character of Christ applied to community life. Christ himself embodied each: compassion (Matt 9:36: moved with compassion for the crowds), kindness (Matt 11:30: my yoke is easy), humility (Matt 11:29: meek and lowly in heart), meekness (the beatitude, Matt 5:5), patience (Heb 12:1-2: with endurance he ran the race). To 'put on' these virtues is to put on Christ (cf. Gal 3:27; Rom 13:14).</p>",
    "13": "<p>'Bearing with one another and, if one has a complaint against another, forgiving each other; as the Lord has forgiven you, so you also must forgive' — the Christological ground of forgiveness: the community forgives 'as the Lord has forgiven you' (<em>kathōs kai ho Christos charisato hymin</em>, using Christos explicitly). The quality and extent of Christ's forgiveness — unlimited (1:14: forgiveness of all sins), unearned (1:21: while enemies), permanent — sets the standard for the community's forgiveness of one another. No offense within the community can exceed what Christ has already forgiven.</p>",
    "14": "<p>'And above all these put on love, which binds everything together in perfect unity' — love as the outer garment that completes and holds together all the other virtues. Christ himself is the love of God enacted in the world (Rom 5:8: God demonstrates his love in that while we were still sinners Christ died for us); the community that 'puts on love' is putting on the character that Christ is and the act that Christ performed. The 'bond of unity' (<em>syndesmos tēs teleiotētos</em>) that love creates mirrors Christ's own role as the one 'in whom all things hold together' (1:17).</p>",
    "15": "<p>'And let the peace of Christ rule in your hearts, to which indeed you were called in one body. And be thankful' — the peace of Christ (<em>hē eirēnē tou Christou</em>) is the reconciliation that Christ accomplished (1:20: making peace by the blood of his cross). This peace — objectively achieved at the cross — is to be the internal governor of the community's decision-making and relational life; where there is conflict, the community returns to the reality of the cross-peace. The 'one body' recalls the body-of-Christ ecclesiology: they were called into the one body of Christ, which is itself defined by his peace.</p>",
    "16": "<p>'Let the word of Christ dwell in you richly, teaching and admonishing one another in all wisdom, singing psalms and hymns and spiritual songs, with thankfulness in your hearts to God' — the 'word of Christ' (<em>ho logos tou Christou</em>) is both the message about Christ and the teaching of Christ himself; it is to inhabit the community richly (<em>plousiōs</em>), producing wisdom, mutual formation, and worship. The psalms, hymns, and spiritual songs are Christological praise: the community fills itself with Christ's word and responds with Christ-directed song (the Colossian hymn of 1:15-20 may exemplify exactly this).</p>",
    "17": "<p>'And whatever you do, in word or deed, do everything in the name of the Lord Jesus, giving thanks to God the Father through him' — the comprehensive Christological claim on every action: 'in the name of the Lord Jesus' means in the authority, character, and identity of the Lord Jesus. Nothing is secular, nothing is too mundane for Christological enactment; every word and act is to be consistent with who Christ is and what he has done. The thanksgiving through him is the Christological mediation of all worship: access to God is through Christ.</p>",
    "18": "<p>'Wives, submit to your husbands, as is fitting in the Lord' — the Christological qualifier 'in the Lord' (<em>en kyriō</em>) transforms the household code's framework: the submission called for is not the world's submission (the Roman hierarchical domination-compliance system) but the Christ-shaped submission that mirrors the mutual deference of the body of Christ. 'As is fitting in the Lord' means the manner and motivation of the submission are governed by Christ's own character — not compulsion but the free self-giving that Christ himself modeled.</p>",
    "19": "<p>'Husbands, love your wives, and do not be harsh with them' — the love commanded is <em>agapaō</em> — the Christ-love defined by self-giving (Eph 5:25: husbands, love your wives as Christ loved the church and gave himself up for her). Harshness (<em>pikrainō</em>) is incompatible with the Christ-love: Christ who was gentle and lowly in heart (Matt 11:29) is the standard against which the husband's treatment of his wife is measured. The brevity of the command is striking: no theological elaboration, just the Christological norm applied directly.</p>",
    "20": "<p>'Children, obey your parents in everything, for this pleases the Lord' — the Lord (Christ) sets the approval standard for family relationships. Obedience to parents is not merely cultural obligation or Roman household management but Christological approval: Christ himself was obedient to his earthly parents (Luke 2:51: he went down with them and came to Nazareth and was submissive to them) and to his heavenly Father (Phil 2:8: obedient to the point of death). The child who obeys participates in the obedience-pattern that Christ himself embodied.</p>",
    "21": "<p>'Fathers, do not provoke your children, lest they become discouraged' — the Christological reflex: Christ welcomed children and identified with the vulnerable (Mark 10:14: let the children come to me; Matt 18:3-4: unless you become like children). To embitter or provoke children contradicts the Christ-character that the father is supposed to embody (3:12: clothe yourselves with compassion, kindness, humility). The Christ who is gentle with the weak demands a corresponding gentleness from fathers toward those in their care.</p>",
    "22": "<p>'Slaves, obey your earthly masters in everything; not by way of eye-service, as people-pleasers, but with sincerity of heart, fearing the Lord' — the Christological reframing of slave-labor: 'fearing the Lord' (<em>phoboumenoi ton kyrion</em>) identifies Christ as the ultimate authority and audience for all work. The 'not as people-pleasers' (<em>mē en ophthalmodouliais</em>) addresses the structural problem of slave-labor: slaves worked when watched, relaxed when not. The Christ-fear inverts this: the slave works with integrity because the Lord Christ is always watching, and the earthly master's gaze is irrelevant to the ultimate quality standard.</p>",
    "23": "<p>'Whatever you do, work at it with your whole heart, as working for the Lord, not for human masters' — the repetition of the Christ-as-employer frame intensifies the point: every task the slave performs — no matter how menial, no matter how invisible to the earthly master — is done before the Lord Christ. This is not just motivation management; it is a Christological ontology of work: all legitimate labor is service to Christ, and Christ receives it as such. The 'whole heart' (<em>ek psychēs</em>) means nothing is held back from the Lord's service.</p>",
    "24": "<p>'Since you know that from the Lord you will receive the inheritance as your reward. You serve the Lord Christ' — the Christological reversal of the slave's situation: under Roman law, slaves had no legal inheritance; under Christ's lordship, they will receive an inheritance from the Lord as a reward. 'Lord Christ' (<em>tō kyriō Christō</em>) combines the two titles in a single phrase: he is the cosmic sovereign (Lord) and the anointed fulfiller of all promise (Christ). The slave who serves him serves the highest authority in the universe and will receive the inheritance that human law denied him.</p>",
    "25": "<p>'For the wrongdoer will be paid back for the wrong he has done, and there is no partiality' — the Christological justice: the eschatological judge (Christ, 2 Cor 5:10: we must all appear before the judgment seat of Christ) shows no partiality (<em>ou prosōpolēmpsia</em>). This no-partiality principle cuts both ways in the slave-master context: the slave who wrongs the master will be judged, but so will the master who wrongs the slave (4:1). The entire system of human hierarchy is flattened before the one judge who sees with perfect equity.</p>"
  },
  "4": {
    "1": "<p>'Masters, provide your slaves with what is right and fair, knowing that you also have a Master in heaven' — the Christological leveling: every earthly master (<em>kyrios</em>) is simultaneously a slave of the heavenly Master (Christ, the same word). The command to provide 'right and fair' treatment is grounded in the identity of the one they serve: Christ the Lord who is just and impartial (3:25). The social hierarchy of master-slave is not abolished but is relativized by both parties standing under the same sovereign whose character is justice.</p>",
    "2": "<p>'Continue steadfastly in prayer, being watchful in it with thanksgiving' — the watchfulness (<em>grēgorountes</em>) is the eschatological posture that Christ demanded of the disciples at Gethsemane (Mark 14:38: watch and pray that you may not enter into temptation). Prayer is the Christological practice of dependence — it is precisely the posture that acknowledges that everything needed comes from God through Christ, not from one's own resources or from cosmic-power negotiations (the Colossian error). Thanksgiving is the Christological response to the sufficiency already received in him.</p>",
    "3": "<p>'And pray for us also, that God may open to us a door for the word, to declare the mystery of Christ, on account of which I am in prison' — Paul's imprisonment is explicitly 'on account of the mystery of Christ' (<em>di ho kai dedemai</em>); his chains are the consequence of proclaiming Christ. The 'open door' metaphor is a resurrection image: the risen Christ is the one who opens what no one can shut (Rev 3:7). The mystery is Christ (2:2), and the entire prayer request is that Paul may have freedom to make Christ known to those who have not yet heard.</p>",
    "4": "<p>'That I may make it clear, as I ought to speak' — the Christological obligation: Paul is under necessity (<em>dei</em>) to make Christ clear. The clarity of proclamation is a pastoral responsibility to the community: Christ must be presented as he actually is — not supplemented by cosmic-power appeasement or ascetic mysticism — so that hearers can receive the full sufficiency of what Christ provides. Paul's prayer for open-door clarity is itself Christological: he is asking for freedom to make Christ fully known.</p>",
    "5": "<p>'Walk in wisdom toward outsiders, making the best use of the time' — the wisdom (<em>sophia</em>) that Paul commands toward outsiders is itself Christological: Christ is the wisdom of God (1 Cor 1:24), and to walk wisely is to walk in a way that reflects the character and priorities of the one in whom all wisdom is hidden (2:3). Christ's own engagement with questioning outsiders — the precision, the counter-question, the parable, the piercing clarity — is the model for the community's missional conversation.</p>",
    "6": "<p>'Let your speech always be gracious, seasoned with salt, so that you may know how to answer each person' — the gracious speech (<em>en chariti</em>) reflects the 'grace and peace' that frames the letter (1:2); it is the speech of people who live in grace and therefore extend grace. Christ himself spoke 'graciously' (<em>tois logois tēs charitos</em>, Luke 4:22), and the community that has received Christ's grace speaks with the same quality. Salt preserves and gives flavor; Christological speech preserves truth and makes it appealing without making it less than it is.</p>",
    "7": "<p>'Tychicus will tell you all the news about me. He is a dear brother and faithful minister and fellow servant in the Lord' — the entire ministerial vocabulary is Christological: 'dear brother' (identity in Christ), 'faithful minister' (<em>diakonos</em>, the same title as Christ's own servant-role, Mark 10:45), 'fellow servant' (<em>syndoulos</em>, shared slavery to Christ). Tychicus's ministry is not his own project; it is participation in Christ's own ongoing work through a human instrument.</p>",
    "8": "<p>'I am sending him to you for this very purpose, that you may know how we are and that he may encourage your hearts' — the sending of Tychicus mirrors the sending pattern established by Christ (John 20:21: as the Father sent me, even so I send you). The ambassador who carries news and encouragement from the apostolic community to the distant churches is the Christological pattern of the Spirit-comforter (Paraclete) expressed through human agency; Tychicus's encouragement of the community's hearts is an extension of the encouragement that Christ himself provides (2 Thess 2:16-17).</p>",
    "9": "<p>'And with him Onesimus, our faithful and beloved brother, who is one of you. They will tell you of everything that has happened here' — the slave Onesimus, whose story is told in the letter to Philemon, is here described simply as 'faithful and beloved brother' — no qualification, no mention of his slave-status. This is the Christological transformation enacted: in Christ, the slave becomes brother (Philem 16: no longer as a slave but better than a slave, as a dear brother, especially to me but how much more to you, both in the flesh and in the Lord). The Christ-logic has rewritten Onesimus's identity completely.</p>",
    "10": "<p>'Aristarchus my fellow prisoner greets you, and Mark the cousin of Barnabas (concerning whom you have received instructions — if he comes to you, welcome him)' — the community gathered around Paul in prison: their shared suffering is the koinōnia in Christ's sufferings (Phil 3:10). Mark, who once abandoned the mission at Pamphylia (Acts 13:13), causing the Barnabas-Paul split (Acts 15:36-41), is here fully restored and commended as a co-laborer. The Christ who restores Peter after the denial (John 21:15-17) is the same Christ who restored Mark; the prison-community is evidence of that grace.</p>",
    "11": "<p>'And Jesus who is called Justus. These are the only men of the circumcision among my co-workers for the kingdom of God, and they have been a comfort to me' — Jewish co-workers laboring alongside Gentile co-workers for the kingdom of God: the Christological mission has dissolved the Jew-Gentile barrier in the community of workers (3:11: here there is no Jew or Greek). Their being a 'comfort' (<em>parēgoria</em>) to Paul in his imprisonment is the Christ-shaped mutual encouragement that the body of Christ provides to its members under pressure.</p>",
    "12": "<p>'Epaphras, who is one of you, a servant of Christ Jesus, greets you, always struggling on your behalf in his prayers, that you may stand mature and fully assured in all the will of God' — Epaphras's intercession for Christological maturity (<em>teleios</em> = mature, complete in Christ, 1:28: present every person mature in Christ). His 'wrestling in prayer' (<em>agōnizomenos</em>) uses the same word as Paul's own striving (1:29: striving according to his working), and both are powered by Christ's energy. His intercession participates in Christ's own high-priestly intercession (Heb 7:25: always lives to make intercession for them).</p>",
    "13": "<p>'For I bear him witness that he has worked hard for you and for those in Laodicea and in Hierapolis' — the hard work (<em>polun ponon</em>) is the Christ-labor: the same toil-vocabulary Paul used in 1:29 for his own ministry powered by Christ's energy. The network of care that Epaphras extends across three cities (Colossae, Laodicea, Hierapolis) is the Christological love that does not limit itself to the immediately visible community but carries responsibility for the whole region where Christ is being proclaimed.</p>",
    "14": "<p>'Luke the beloved physician greets you, and so does Demas' — Luke, who will preserve the Christological narrative in the Gospel and the Acts of the Apostles that bear his historical and theological work, appears here simply as 'beloved physician' — his identity in the community is 'beloved,' the same quality of relationship that characterizes all genuine participation in the body of Christ (1:7: our dear fellow servant; 4:7: dear brother). Even in a brief greeting, the Christological relational quality is the primary description.</p>",
    "15": "<p>'Give my greetings to the brothers and sisters at Laodicea, and to Nympha and the church in her house' — the household church: the community of Christ gathering in Nympha's home. The house-church network in the Lycus Valley (Colossae, Laodicea, Hierapolis) is the distributed body of Christ; the greetings that travel between them are expressions of the one body's solidarity across multiple locations. Nympha as house-church patron represents the women who provided the spatial and economic foundation for the early Christ-communities.</p>",
    "16": "<p>'And when this letter has been read among you, see that it is also read in the church of the Laodiceans, and that you yourselves read the letter from Laodicea' — the circulation of Christological teaching across the network: Paul's letter is not private correspondence but community Scripture, designed to form all the Christ-communities of the region. The mutual exchange of letters (Colossians reads the Laodicean letter; Laodiceans read Colossians) embodies the principle of 3:16: the word of Christ dwelling richly as each community teaches and admonishes the others.</p>",
    "17": "<p>'And say to Archippus: see that you fulfill the ministry that you have received in the Lord' — the ministry 'received in the Lord' (<em>en kyriō</em>) is a Christological gift and commission: Archippus did not devise his own ministry but received it through and in Christ. The fulfillment (<em>plēroō</em>) that Paul commands uses the same root as the fullness (<em>plēroma</em>) language throughout the letter: to fulfill the ministry is to bring it to completion, as Christ himself brought to completion the work the Father gave him (John 17:4: I glorified you on earth, having accomplished the work you gave me to do).</p>",
    "18": "<p>'I, Paul, write this greeting with my own hand. Remember my chains. Grace be with you' — Paul's chains are the chains of Christ: his imprisonment is 'on account of the mystery of Christ' (v.3), the consequence of proclaiming the one who is himself the mystery (2:2). The grace that Paul invokes is the grace of Christ (2 Cor 13:14: the grace of the Lord Jesus Christ). The letter that opened with 'grace and peace' (1:2) closes with 'grace' — the entire letter is enclosed within and defined by the Christological gift. To remember Paul's chains is to remember that the gospel of Christ's sufficiency costs something to proclaim.</p>"
  }
}

if __name__ == '__main__':
    existing = load_comm('mkt-christ', 'colossians')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'colossians', existing)
    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'colossians.json'))
    all_ok = True
    for ch in range(1, 5):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(existing.get(ck, {}).keys())
        if missing:
            print(f'  ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch {ch}: complete ({len(existing.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')
